Here's how to structure your MSTest tests for `DataFetcher`, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.ResponseContent = "hello";
        _handler.StatusCode = HttpStatusCode.OK;

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        _handler.StatusCode = HttpStatusCode.InternalServerError;

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        _handler.Delay = TimeSpan.FromSeconds(30);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // guard against hangs
    public async Task FetchAsync_WithTimeout_CompletesBeforeDeadline()
    {
        _handler.ResponseContent = "fast";
        _handler.StatusCode = HttpStatusCode.OK;

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await _sut.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Minimal test double â€” swap out the HTTP pipeline without a mocking framework
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpMessageMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(Delay, cancellationToken);
            return new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` fields, satisfies nullability |
| `TestContext.CancellationToken` | Cooperative timeout â€” `[Timeout]` cancels this token |
| `Assert.ThrowsExactlyAsync<T>` | Preferred over `[ExpectedException]`; lets you inspect the exception |
| Custom `HttpMessageHandler` | Avoids mocking `HttpClient` directly (which doesn't work well) |
| `sealed` test class | MSTest best practice for performance |
| `[Timeout(5000)]` | Prevents test from hanging indefinitely |

**The cancellation flow:** `[Timeout]` fires â†’ `TestContext.CancellationToken` is cancelled â†’ your async call observes the token and throws `TaskCanceledException` â†’ MSTest reports a timeout failure instead of a hang.
